import { useEffect, useState } from "react";
import { Player } from "../../objects/player";
import { GetPlayerGameStats } from "../../services/game-stat-service";
import { GameStat } from "../../objects/game-stat";
import { GetTotalAssists, GetTotalGSO, GetTotalGames, GetTotalGoals, GetTotalShots, GetTotalTackles } from "../../utils/game-stats-util";

interface playerProps{
    player : Player
}

const PlayerCard = (playerProps : playerProps) => {     

    const [gameStats, setGameStats] = useState<GameStat[] | null>(null);
    const [totalGames, setTotalGame] = useState(0);
    const [totalGoals, setGoals] = useState(0);
    const [totalAssist, setAssistGoals] = useState(0);
    const [totalGSOs, setGSOs] = useState(0);
    const [totalTackles, setTackles] = useState(0);
    const [totalShots, setShots] = useState(0);

    useEffect(() => {
        GetPlayerGameStats(playerProps.player.id).then(gameStats => setGameStats(gameStats));
        
    }, [playerProps.player.id]);

    useEffect(() => {
        if (gameStats != null)
        {
            setTotalGame(GetTotalGames({gameStats : gameStats}));
            setGoals(GetTotalGoals({gameStats : gameStats}));
            setAssistGoals(GetTotalAssists({gameStats : gameStats}));
            setGSOs(GetTotalGSO({gameStats : gameStats}));
            setTackles(GetTotalTackles({gameStats : gameStats}));
            setShots(GetTotalShots({gameStats : gameStats}));
        }
    }, [gameStats]);    

    var position = "";
    switch(playerProps.player.position)  
    {
        case 0: 
            position = "GK";
            break;

        case 1: 
            position = "Def";
            break;

        case 2: 
            position = "Mid";
            break;

        case 3: 
            position = "Str";
            break;

    }

    return(   
        <div className="col-sm-3">
            <div className="card">
                <div className="card-body">
                    <h5 className="card-title">{playerProps.player.firstname} {playerProps.player.surname} </h5>  
                    <table>
                        <thead>
                            <th>Apps</th>
                            <th>Gls</th>
                            <th>Assists</th>
                            <th>GSO</th>
                            <th>Shots</th>
                            <th>Tackles</th>
                            <th>Position</th>
                        </thead>
                        <tbody>
                            <td>{totalGames}</td>
                            <td>{totalGoals}</td>
                            <td>{totalAssist}</td>
                            <td>{totalGSOs}</td>                            
                            <td>{totalShots}</td>
                            <td>{totalTackles}</td>
                            <td>{position}</td>
                        </tbody>
                    </table>                     
                </div>
            </div>
        </div>        
    )
}
export default PlayerCard;
